import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

function Header() {
  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  return (
    <header className="bg-white shadow-md py-4 rtl">
      <div className="container mx-auto flex justify-between items-center px-4">
        <div className="text-2xl font-bold">
          <Link to="/">تحلیل بورس</Link>
        </div>
        
        <nav>
          <ul className="flex">
            <li className="ml-5">
              <Link to="/" className="block py-1 font-medium hover:text-blue-500">خانه</Link>
            </li>
            {isAuthenticated ? (
              <li className="ml-5">
                <Link to="/dashboard" className="block py-1 font-medium hover:text-blue-500">داشبورد</Link>
              </li>
            ) : null}
          </ul>
        </nav>
        
        <div className="flex items-center">
          {isAuthenticated ? (
            <div className="flex items-center">
              {user?.photo && (
                <img 
                  src={user.photo} 
                  alt={user.displayName} 
                  className="w-8 h-8 rounded-full ml-2" 
                />
              )}
              <span className="ml-2 font-medium">{user?.displayName}</span>
              <button onClick={handleLogout} className="btn-logout ml-4">
                خروج
              </button>
            </div>
          ) : (
            <Link to="/login" className="btn btn-primary">
              ورود
            </Link>
          )}
        </div>
      </div>
    </header>
  );
}

export default Header;
